   459	EmitIR::operator()(FunctionDecl* obj)
   460	{
   461	  auto func = llvm::dyn_cast<llvm::Function>(mDeclMap[obj]);
   462	  if (!func)
   463	    ABORT();
   464	
   465	  auto fty = func->getFunctionType();
   466	
   467	  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
   468	  mCurIrb->SetInsertPoint(entryBb);
   469	  auto& irb = *mCurIrb;
   470	
   471	  // Allocate space for parameters and store them
   472	  auto argIt = func->arg_begin();
   473	  for (size_t i = 0; i < obj->params.size() && argIt != func->arg_end(); ++i, ++argIt) {
   474	    auto param = obj->params[i];
   475	    auto vd = param->dcst<VarDecl>();
   476	    if (vd) {
   477	      auto paramTy = self(vd->type);
   478	      auto alloca = createAlloca(paramTy, vd->name);
   479	      irb.CreateStore(&*argIt, alloca);
   480	      mDeclMap[vd] = alloca;
   481	    }
   482	  }
   483	
   484	  mCurFunc = func;
   485	  self(obj->body);
   486	
   487	  // Ensure the last block has a terminator
   488	  auto& exitIrb = *mCurIrb;
   489	  auto lastBb = exitIrb.GetInsertBlock();
   490	  if (!lastBb->getTerminator()) {
   491	    if (fty->getReturnType()->isVoidTy())
   492	      exitIrb.CreateRetVoid();
   493	    else
   494	      exitIrb.CreateRet(llvm::ConstantInt::get(fty->getReturnType(), 0));
