   544	EmitIR::storeInit(llvm::Value* ptr, Expr* init, const Type* type)
   545	{
   546	  auto& irb = *mCurIrb;
   547	
   548	  if (auto il = init->dcst<IntegerLiteral>()) {
   549	    irb.CreateStore(llvm::ConstantInt::get(self(type), il->val), ptr);
   550	  } else if (auto ile = init->dcst<ImplicitInitExpr>()) {
   551	    irb.CreateStore(llvm::ConstantInt::get(self(type), 0), ptr);
