   558	        auto idx = llvm::ConstantInt::get(mIntTy, i);
   559	        auto elemPtr = irb.CreateInBoundsGEP(arrTy, ptr, { llvm::ConstantInt::get(mIntTy, 0), idx });
   560	        storeInit(elemPtr, initList->list[i], type); // recurse with same type (will get sub type)
   561	      }
   562	      // Zero-initialize remaining elements
   563	      for (size_t i = initList->list.size(); i < arrTy->getNumElements(); ++i) {
   564	        auto idx = llvm::ConstantInt::get(mIntTy, i);
   565	        auto elemPtr = irb.CreateInBoundsGEP(arrTy, ptr, { llvm::ConstantInt::get(mIntTy, 0), idx });
   566	        irb.CreateStore(llvm::ConstantInt::get(elemTy, 0), elemPtr);
   567	      }
   568	    }
